var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"고생했네. 물건은 전부 무사하더군.","JPN":"ご苦労だった。荷物はすべて無事であったな。","ENG":"Good work. All the cargo made it intact.","TWN":"辛苦了，東西都完好無缺。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"장난해? 우린 그쪽이 부탁한 물건 때문에 침식체한테 쫓겨서 죽을 뻔했다고!","JPN":"何が無事だ！　こっちはその荷物のせいで侵食体に追われて死ぬところだったんだぞ！","ENG":"Are you kidding me?! We almost died hauling your stuff!","TWN":"你在開玩笑嗎？為了送這些東西，我們被侵蝕體追殺，差點命都沒了！"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"쫓길 각오는 한 줄 알았네만.","JPN":"追われる覚悟はできているのかと思ったが。","ENG":"I assumed you were prepared for pursuit.","TWN":"我以為你們答應時就知道會有危險。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"계약에 침식체가 몰려들 거란 내용은 없었잖아!","JPN":"侵食体が押し寄せてくるなんて契約書には書いてなかったじゃないか！","ENG":"No one said C.O.s would swarm us!","TWN":"合約上沒有寫會被侵蝕體追殺吧！"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그건 그대가 계약을 따르지 않았기 때문일세.","JPN":"それはそなたが契約に従わなかったからである。","ENG":"That's because you didn't follow the contract.","TWN":"那是你自己沒有遵守合約。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이터니움을 셋으로 소분해서 서로 다른 시간에 배달해 달라는 지침을 따르지 않았더군.","JPN":"エタニウムを3つに小分けして別々の時間帯に配送するという指針があっただろう。","ENG":"You were supposed to deliver the Eternium in three separate runs.","TWN":"我叫你把永恆之金分成三份運送，你卻沒有照做。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"어…?","JPN":"え……？","ENG":"Huh…?","TWN":"嗯…？"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"물론 세 차례에 걸쳐 배달할 물건을 그대처럼 한 번에 실어 나르면 비용은 훨씬 절감할 수 있겠지.","JPN":"無論、3回に分けて配送する荷物を、そなたのようにまとめて運ぶとなれば費用を大きく節減できる。","ENG":"Sure, it's cheaper to haul it all at once, like you did.","TWN":"當然，像你這樣把三次運送的東西一次運完，可以省下很多成本。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"허나 이곳으로 오는 중턱 길목은 차원벽이 약해 작은 자극만으로도 침식을 끌어들인다네.","JPN":"しかしここに来る途中にある山腹道路は次元壁が脆く、少しの刺激で侵食をおびき寄せるのでな。","ENG":"But that mountain pass has a thin dimensional wall. Even the slightest change and the C.O.s will come running.","TWN":"但這裡，這條山路，次元壁很薄，只要一點點刺激都會引來侵蝕。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그 정도 양의 이터니움을 한 번에 가져오면 침식체가 나타나는 건 당연한 결과지.","JPN":"あれだけの量のエタニウムをまとめて運べば、侵食体が現れるのは至極当然のことだ。","ENG":"You brought this on yourselves bringing that much Eternium at once.","TWN":"一次帶這麼多永恆之金，會出現侵蝕體是理所當然的。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"대장… 계속 우겼다간 본전도 못 찾겠는데요?","JPN":"隊長……言い争ったところで勝つ見込みはありませんよ。","ENG":"Boss… we're not getting out of this with full pay if we keep complainin'.","TWN":"隊長…少說一句吧，免得到時候我們什麼連本錢都賺不回來。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"끙…","JPN":"ぐぬぬ……","ENG":"Ugh…","TWN":"嘖…"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"알겠어. 내 책임도 조금은 있으니 그 부분은 넘어가지.","JPN":"まあ、そこは俺の責任も少しはあるからいいとしてだ。","ENG":"Fine. I'll take my share of the blame.","TWN":"好吧。這部分我也有點責任，就不跟你計較了。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DRIVER_NPC_NULL_14","text":{"KOREA":"잠깐. 의뢰인에게 그런 요청이 있었단 얘기, 난 처음 듣는데?!","JPN":"待て。依頼人からそんな要望があったなんて話、俺は初耳だが！？","ENG":"Hold up. I didn't hear about any three runs part.","TWN":"等一下，我怎麼不知道委託人有這麼說過？"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DRIVER_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"윽…","JPN":"ぐっ……","ENG":"Guh…","TWN":"呃…"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DRIVER_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"아, 알겠어! 위험수당 더 쳐주면 되잖아!","JPN":"わ、分かった！　危険手当をもっとつけてやるから！","ENG":"All right, fine! I'll tack on hazard pay. Happy?!","TWN":"好啦好啦！我再多貼錢給你啦！"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DRIVER_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"쳇, 돈 좀 아끼려다가 본전도 못 찾게 생겼군.","JPN":"ちっ、ケチって済まそうとしたら、元も取れそうにないな。","ENG":"Damn it. Trying to cut corners cost me everything.","TWN":"嘖，本來想省點錢，結果得不償失。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DRIVER_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저기요-","JPN":"あの～","ENG":"Hey.","TWN":"那個…"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"뭐? 또 왜?","JPN":"何だ？　まだ何かあるのか？","ENG":"What now?!","TWN":"幹嘛？又怎麼了？"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"제가 목숨 걸고 아저씨들을 지켜줬는데, 설마 맨입으로 넘어가려는 건 아니죠?","JPN":"まさかおじさんたち、ただで助けてもらったなんて思ってないですよね？","ENG":"You don't think I saved your butts for free, right?","TWN":"你們該不會以為我救你們是免費的吧？"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"그… 그러니까…","JPN":"その……それは……","ENG":"S-so…","TWN":"這…這個…"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"아가씨가 우리 사정 좀 봐줘! 이미 탄약 값도 안 남는다고!","JPN":"こっちの事情も汲んでくれよ！　こんなんじゃ弾代も残らないぞ！","ENG":"Oh, come on! Cut us some slack! We barely have enough for ammo!","TWN":"小妹妹，你也體諒一下我們！這樣我們連子彈的錢都賺不回來！"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그거야 멋대로 요청사항을 어긴 아저씨들 사정…","JPN":"それは勝手に要望を無視したおじさんたちが悪い……","ENG":"Well, you broke the contract. So…","TWN":"誰叫你們自己不遵守合約…"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…이라고 매몰차게 굴 수도 있지만, 다른 방법이 있긴 해요.","JPN":"……と、冷たく当たるのもできますけど。一応、別の方法もあるんです。","ENG":"…I could just be ruthless about it, but I have another idea.","TWN":"…我是可以這麼說，但還有別的方法。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"다른 방법? 그게 뭔데?","JPN":"別の方法？　なんだそれは？","ENG":"Another idea? What is it?","TWN":"別的方法？是什麼？"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"후후, 돈이 없으면 몸으로 떼워야죠.","JPN":"ふふ……お金で払えないなら、体で払ってもらわないと。","ENG":"Hehe. If you can't pay up, work it off.","TWN":"呵呵，付不起錢的話，就用身體來償還吧。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"모, 몸으로…?","JPN":"か、体で……？","ENG":"W-work it off…?","TWN":"用，用身體…？"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};